/**
 * Auth Module Service Tests
 *
 * Unit tests for AuthModuleService covering:
 * - User registration
 * - Login authentication
 * - Token refresh
 * - Logout
 * - Password reset flow
 * - Email verification flow
 * - Password change
 * - Session management
 *
 * @module modules/_core/auth/__tests__/auth.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';
import { UserStatus } from '@prisma/client';

import { AuthModuleService } from '@/modules/_core/auth/auth.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { AuthService, TokenUser } from '@/core/services/auth.service';
import type { EventService } from '@/core/services/event.service';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock PrismaClient
 */
function createMockPrisma() {
  return {
    user: {
      findFirst: vi.fn(),
      findUnique: vi.fn(),
      findMany: vi.fn(),
      create: vi.fn(),
      update: vi.fn(),
      delete: vi.fn(),
    },
  };
}

/**
 * Creates a mock AuthService (core)
 */
function createMockAuthService(): {
  hashPassword: Mock;
  verifyPassword: Mock;
  generateTokenPair: Mock;
  generateEmailVerificationToken: Mock;
  generatePasswordResetToken: Mock;
  verifyPasswordResetToken: Mock;
  invalidatePasswordResetToken: Mock;
  verifyEmailVerificationToken: Mock;
  invalidateEmailVerificationToken: Mock;
  refreshAccessToken: Mock;
  revokeAllUserTokens: Mock;
  getUserSessions: Mock;
} {
  return {
    hashPassword: vi.fn(),
    verifyPassword: vi.fn(),
    generateTokenPair: vi.fn(),
    generateEmailVerificationToken: vi.fn(),
    generatePasswordResetToken: vi.fn(),
    verifyPasswordResetToken: vi.fn(),
    invalidatePasswordResetToken: vi.fn(),
    verifyEmailVerificationToken: vi.fn(),
    invalidateEmailVerificationToken: vi.fn(),
    refreshAccessToken: vi.fn(),
    revokeAllUserTokens: vi.fn(),
    getUserSessions: vi.fn(),
  };
}

/**
 * Creates a mock EventService
 */
function createMockEventService(): {
  emitCustom: Mock;
} {
  return {
    emitCustom: vi.fn(),
  };
}

/**
 * Creates a mock user for testing
 */
function createMockUser(overrides: Partial<{
  id: string;
  email: string;
  passwordHash: string;
  firstName: string;
  lastName: string;
  phone: string | null;
  avatar: string | null;
  organizationId: string | null;
  status: UserStatus;
  emailVerifiedAt: Date | null;
  lastLoginAt: Date | null;
  createdAt: Date;
  updatedAt: Date;
  deletedAt: Date | null;
  userRoles: Array<{
    role: {
      id: string;
      name: string;
      rolePermissions: Array<{
        permission: {
          resource: string;
          action: string;
        };
      }>;
    };
  }>;
}> = {}) {
  return {
    id: 'user_123',
    email: 'test@example.com',
    passwordHash: 'hashed_password',
    firstName: 'John',
    lastName: 'Doe',
    phone: null,
    avatar: null,
    organizationId: 'org_123',
    status: UserStatus.ACTIVE,
    emailVerifiedAt: new Date(),
    lastLoginAt: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    userRoles: [
      {
        role: {
          id: 'role_1',
          name: 'owner',
          rolePermissions: [
            {
              permission: {
                resource: 'menu',
                action: 'view',
              },
            },
            {
              permission: {
                resource: 'menu',
                action: 'create',
              },
            },
          ],
        },
      },
    ],
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('AuthModuleService', () => {
  let service: AuthModuleService;
  let mockPrisma: ReturnType<typeof createMockPrisma>;
  let mockAuthService: ReturnType<typeof createMockAuthService>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  beforeEach(() => {
    mockPrisma = createMockPrisma();
    mockAuthService = createMockAuthService();
    mockEventService = createMockEventService();

    service = new AuthModuleService(
      mockPrisma as unknown as Parameters<typeof AuthModuleService['prototype']['constructor']>[0],
      mockAuthService as unknown as AuthService,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // Registration Tests
  // ---------------------------------------------------------------------------

  describe('register', () => {
    const validRegisterData = {
      email: 'newuser@example.com',
      password: 'SecurePassword123!',
      passwordConfirm: 'SecurePassword123!',
      firstName: 'Jane',
      lastName: 'Smith',
      phone: '+905551234567',
      acceptTerms: true,
    };

    it('should register a new user successfully', async () => {
      // Arrange
      mockPrisma.user.findFirst.mockResolvedValue(null);
      mockAuthService.hashPassword.mockResolvedValue('hashed_new_password');
      mockPrisma.user.create.mockResolvedValue({
        id: 'user_new',
        email: validRegisterData.email,
        firstName: validRegisterData.firstName,
        lastName: validRegisterData.lastName,
      });
      mockAuthService.generateEmailVerificationToken.mockResolvedValue('verify_token_123');
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.register(validRegisterData);

      // Assert
      expect(result).toEqual({
        userId: 'user_new',
        email: validRegisterData.email,
        requiresEmailVerification: true,
        message: expect.any(String),
      });

      expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({
        where: expect.objectContaining({
          email: validRegisterData.email,
        }),
      });

      expect(mockAuthService.hashPassword).toHaveBeenCalledWith(validRegisterData.password);

      expect(mockPrisma.user.create).toHaveBeenCalledWith({
        data: expect.objectContaining({
          email: validRegisterData.email,
          firstName: validRegisterData.firstName,
          lastName: validRegisterData.lastName,
          status: UserStatus.INVITED,
        }),
      });

      expect(mockAuthService.generateEmailVerificationToken).toHaveBeenCalled();
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'auth.user.registered',
        expect.objectContaining({
          userId: 'user_new',
          email: validRegisterData.email,
        })
      );
    });

    it('should throw error when email already exists', async () => {
      // Arrange
      mockPrisma.user.findFirst.mockResolvedValue(createMockUser({ email: validRegisterData.email }));

      // Act & Assert
      await expect(service.register(validRegisterData)).rejects.toThrow(AppException);

      expect(mockPrisma.user.create).not.toHaveBeenCalled();
    });

    it('should throw validation error when email is invalid', async () => {
      // Arrange
      const invalidData = {
        ...validRegisterData,
        email: 'invalid-email',
      };

      // Act & Assert
      await expect(service.register(invalidData)).rejects.toThrow(AppException);
    });

    it('should throw validation error when passwords do not match', async () => {
      // Arrange
      const invalidData = {
        ...validRegisterData,
        passwordConfirm: 'DifferentPassword123!',
      };

      // Act & Assert
      await expect(service.register(invalidData)).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Login Tests
  // ---------------------------------------------------------------------------

  describe('login', () => {
    const validLoginData = {
      email: 'test@example.com',
      password: 'CorrectPassword123!',
    };

    const mockTokens = {
      accessToken: 'access_token_123',
      refreshToken: 'refresh_token_456',
      expiresIn: 900000,
      tokenType: 'Bearer' as const,
    };

    it('should login user successfully with valid credentials', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockPrisma.user.findFirst.mockResolvedValue(mockUser);
      mockAuthService.verifyPassword.mockResolvedValue(true);
      mockAuthService.generateTokenPair.mockResolvedValue(mockTokens);
      mockPrisma.user.update.mockResolvedValue(mockUser);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.login(validLoginData, {
        ipAddress: '127.0.0.1',
        userAgent: 'Test Agent',
      });

      // Assert
      expect(result).toEqual({
        user: expect.objectContaining({
          id: mockUser.id,
          email: mockUser.email,
          firstName: mockUser.firstName,
          lastName: mockUser.lastName,
          role: 'owner',
        }),
        tokens: mockTokens,
      });

      expect(mockAuthService.verifyPassword).toHaveBeenCalledWith(
        validLoginData.password,
        mockUser.passwordHash
      );

      expect(mockAuthService.generateTokenPair).toHaveBeenCalledWith(
        expect.objectContaining({
          id: mockUser.id,
          organizationId: mockUser.organizationId,
        }),
        expect.objectContaining({
          ipAddress: '127.0.0.1',
          userAgent: 'Test Agent',
        })
      );

      expect(mockPrisma.user.update).toHaveBeenCalledWith({
        where: { id: mockUser.id },
        data: { lastLoginAt: expect.any(Date) },
      });

      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'auth.login',
        expect.objectContaining({
          userId: mockUser.id,
        })
      );
    });

    it('should throw error when user not found', async () => {
      // Arrange
      mockPrisma.user.findFirst.mockResolvedValue(null);

      // Act & Assert
      await expect(service.login(validLoginData)).rejects.toThrow(AppException);

      expect(mockAuthService.verifyPassword).not.toHaveBeenCalled();
    });

    it('should throw error when password is incorrect', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockPrisma.user.findFirst.mockResolvedValue(mockUser);
      mockAuthService.verifyPassword.mockResolvedValue(false);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act & Assert
      await expect(service.login(validLoginData)).rejects.toThrow(AppException);

      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'auth.login.failed',
        expect.objectContaining({
          email: validLoginData.email,
        })
      );
    });

    it('should throw error when user account is suspended', async () => {
      // Arrange
      const suspendedUser = createMockUser({ status: UserStatus.SUSPENDED });
      mockPrisma.user.findFirst.mockResolvedValue(suspendedUser);

      // Act & Assert
      await expect(service.login(validLoginData)).rejects.toThrow(AppException);

      expect(mockAuthService.verifyPassword).not.toHaveBeenCalled();
    });

    it('should return emailVerified false when email not verified', async () => {
      // Arrange
      const unverifiedUser = createMockUser({ emailVerifiedAt: null });
      mockPrisma.user.findFirst.mockResolvedValue(unverifiedUser);
      mockAuthService.verifyPassword.mockResolvedValue(true);
      mockAuthService.generateTokenPair.mockResolvedValue(mockTokens);
      mockPrisma.user.update.mockResolvedValue(unverifiedUser);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.login(validLoginData);

      // Assert
      expect(result.user.emailVerified).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // Refresh Token Tests
  // ---------------------------------------------------------------------------

  describe('refreshTokens', () => {
    it('should refresh tokens successfully', async () => {
      // Arrange
      const newTokens = {
        accessToken: 'new_access_token',
        refreshToken: 'new_refresh_token',
        expiresIn: 900000,
        tokenType: 'Bearer' as const,
      };
      mockAuthService.refreshAccessToken.mockResolvedValue(newTokens);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.refreshTokens('valid_refresh_token');

      // Assert
      expect(result).toEqual({ tokens: newTokens });
      expect(mockAuthService.refreshAccessToken).toHaveBeenCalledWith(
        'valid_refresh_token',
        expect.any(Function)
      );
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'auth.token.refresh',
        expect.any(Object)
      );
    });

    it('should throw error when refresh token is empty', async () => {
      // Act & Assert
      await expect(service.refreshTokens('')).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Logout Tests
  // ---------------------------------------------------------------------------

  describe('logout', () => {
    it('should logout user from single device', async () => {
      // Arrange
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.logout('user_123', 'token_id_456', { allDevices: false });

      // Assert
      expect(result.message).toContain('logged out');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'auth.logout',
        expect.objectContaining({
          userId: 'user_123',
          tokenId: 'token_id_456',
        })
      );
    });

    it('should logout user from all devices', async () => {
      // Arrange
      mockAuthService.revokeAllUserTokens.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.logout('user_123', 'token_id_456', { allDevices: true });

      // Assert
      expect(result.message).toContain('all devices');
      expect(mockAuthService.revokeAllUserTokens).toHaveBeenCalledWith('user_123');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'auth.session.revoked.all',
        expect.objectContaining({
          userId: 'user_123',
        })
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Password Reset Tests
  // ---------------------------------------------------------------------------

  describe('forgotPassword', () => {
    it('should return success message when user exists', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockPrisma.user.findFirst.mockResolvedValue(mockUser);
      mockAuthService.generatePasswordResetToken.mockResolvedValue('reset_token_123');
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.forgotPassword({ email: 'test@example.com' });

      // Assert
      expect(result.message).toBeDefined();
      expect(mockAuthService.generatePasswordResetToken).toHaveBeenCalledWith(
        mockUser.id,
        mockUser.email
      );
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'auth.password.reset.requested',
        expect.objectContaining({
          userId: mockUser.id,
        })
      );
    });

    it('should return success message even when user does not exist (prevent enumeration)', async () => {
      // Arrange
      mockPrisma.user.findFirst.mockResolvedValue(null);

      // Act
      const result = await service.forgotPassword({ email: 'nonexistent@example.com' });

      // Assert
      expect(result.message).toBeDefined();
      expect(mockAuthService.generatePasswordResetToken).not.toHaveBeenCalled();
    });
  });

  describe('resetPassword', () => {
    const validResetData = {
      token: 'valid_reset_token',
      password: 'NewSecurePassword123!',
      passwordConfirm: 'NewSecurePassword123!',
    };

    it('should reset password successfully', async () => {
      // Arrange
      const tokenData = { userId: 'user_123', email: 'test@example.com', createdAt: new Date().toISOString() };
      mockAuthService.verifyPasswordResetToken.mockResolvedValue(tokenData);
      mockAuthService.hashPassword.mockResolvedValue('new_hashed_password');
      mockPrisma.user.update.mockResolvedValue(createMockUser());
      mockAuthService.invalidatePasswordResetToken.mockResolvedValue(undefined);
      mockAuthService.revokeAllUserTokens.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.resetPassword(validResetData);

      // Assert
      expect(result.message).toContain('successfully');
      expect(mockAuthService.verifyPasswordResetToken).toHaveBeenCalledWith(validResetData.token);
      expect(mockAuthService.hashPassword).toHaveBeenCalledWith(validResetData.password);
      expect(mockPrisma.user.update).toHaveBeenCalledWith({
        where: { id: tokenData.userId },
        data: { passwordHash: 'new_hashed_password' },
      });
      expect(mockAuthService.invalidatePasswordResetToken).toHaveBeenCalledWith(validResetData.token);
      expect(mockAuthService.revokeAllUserTokens).toHaveBeenCalledWith(tokenData.userId);
    });

    it('should throw error when reset token is invalid', async () => {
      // Arrange
      mockAuthService.verifyPasswordResetToken.mockRejectedValue(
        new AppException('INVALID_RESET_TOKEN', 401)
      );

      // Act & Assert
      await expect(service.resetPassword(validResetData)).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Email Verification Tests
  // ---------------------------------------------------------------------------

  describe('verifyEmail', () => {
    it('should verify email successfully', async () => {
      // Arrange
      const tokenData = { userId: 'user_123', email: 'test@example.com', createdAt: new Date().toISOString() };
      mockAuthService.verifyEmailVerificationToken.mockResolvedValue(tokenData);
      mockPrisma.user.update.mockResolvedValue(createMockUser({ emailVerifiedAt: new Date() }));
      mockAuthService.invalidateEmailVerificationToken.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.verifyEmail({ token: 'valid_verification_token' });

      // Assert
      expect(result.verified).toBe(true);
      expect(mockPrisma.user.update).toHaveBeenCalledWith({
        where: { id: tokenData.userId },
        data: {
          emailVerifiedAt: expect.any(Date),
          status: UserStatus.ACTIVE,
        },
      });
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'auth.email.verification.completed',
        expect.objectContaining({
          userId: tokenData.userId,
          email: tokenData.email,
        })
      );
    });

    it('should throw error when verification token is invalid', async () => {
      // Arrange
      mockAuthService.verifyEmailVerificationToken.mockRejectedValue(
        new AppException('INVALID_TOKEN', 401)
      );

      // Act & Assert
      await expect(service.verifyEmail({ token: 'invalid_token' })).rejects.toThrow(AppException);
    });
  });

  describe('resendVerification', () => {
    it('should resend verification email when user exists and not verified', async () => {
      // Arrange
      const mockUser = createMockUser({ emailVerifiedAt: null });
      mockPrisma.user.findFirst.mockResolvedValue(mockUser);
      mockAuthService.generateEmailVerificationToken.mockResolvedValue('new_verify_token');
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.resendVerification({ email: mockUser.email });

      // Assert
      expect(result.message).toBeDefined();
      expect(mockAuthService.generateEmailVerificationToken).toHaveBeenCalledWith(
        mockUser.id,
        mockUser.email
      );
    });

    it('should return success even when user does not exist (prevent enumeration)', async () => {
      // Arrange
      mockPrisma.user.findFirst.mockResolvedValue(null);

      // Act
      const result = await service.resendVerification({ email: 'nonexistent@example.com' });

      // Assert
      expect(result.message).toBeDefined();
      expect(mockAuthService.generateEmailVerificationToken).not.toHaveBeenCalled();
    });

    it('should return success even when user is already verified (prevent enumeration)', async () => {
      // Arrange
      const verifiedUser = createMockUser({ emailVerifiedAt: new Date() });
      mockPrisma.user.findFirst.mockResolvedValue(verifiedUser);

      // Act
      const result = await service.resendVerification({ email: verifiedUser.email });

      // Assert
      expect(result.message).toBeDefined();
      expect(mockAuthService.generateEmailVerificationToken).not.toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Change Password Tests
  // ---------------------------------------------------------------------------

  describe('changePassword', () => {
    const validChangePasswordData = {
      currentPassword: 'CurrentPassword123!',
      newPassword: 'NewSecurePassword456!',
      newPasswordConfirm: 'NewSecurePassword456!',
    };

    it('should change password successfully', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockPrisma.user.findUnique.mockResolvedValue(mockUser);
      mockAuthService.verifyPassword.mockResolvedValue(true);
      mockAuthService.hashPassword.mockResolvedValue('new_hashed_password');
      mockPrisma.user.update.mockResolvedValue(mockUser);
      mockAuthService.revokeAllUserTokens.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.changePassword(mockUser.id, validChangePasswordData);

      // Assert
      expect(result.message).toContain('successfully');
      expect(result.sessionsRevoked).toBe(true);
      expect(mockAuthService.verifyPassword).toHaveBeenCalledWith(
        validChangePasswordData.currentPassword,
        mockUser.passwordHash
      );
      expect(mockAuthService.hashPassword).toHaveBeenCalledWith(validChangePasswordData.newPassword);
      expect(mockAuthService.revokeAllUserTokens).toHaveBeenCalledWith(mockUser.id);
    });

    it('should throw error when user not found', async () => {
      // Arrange
      mockPrisma.user.findUnique.mockResolvedValue(null);

      // Act & Assert
      await expect(service.changePassword('nonexistent_user', validChangePasswordData)).rejects.toThrow(
        AppException
      );
    });

    it('should throw error when current password is incorrect', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockPrisma.user.findUnique.mockResolvedValue(mockUser);
      mockAuthService.verifyPassword.mockResolvedValue(false);

      // Act & Assert
      await expect(service.changePassword(mockUser.id, validChangePasswordData)).rejects.toThrow(
        AppException
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Session Management Tests
  // ---------------------------------------------------------------------------

  describe('getSessions', () => {
    it('should return user sessions with current session marked', async () => {
      // Arrange
      const mockSessions = [
        {
          tokenId: 'token_1',
          userId: 'user_123',
          organizationId: 'org_123',
          role: 'owner',
          ipAddress: '192.168.1.1',
          userAgent: 'Chrome',
          createdAt: new Date().toISOString(),
          lastActivityAt: new Date().toISOString(),
        },
        {
          tokenId: 'token_2',
          userId: 'user_123',
          organizationId: 'org_123',
          role: 'owner',
          ipAddress: '192.168.1.2',
          userAgent: 'Firefox',
          createdAt: new Date().toISOString(),
          lastActivityAt: new Date().toISOString(),
        },
      ];
      mockAuthService.getUserSessions.mockResolvedValue(mockSessions);

      // Act
      const result = await service.getSessions('user_123', 'token_1');

      // Assert
      expect(result).toHaveLength(2);
      expect(result[0]?.isCurrent).toBe(true);
      expect(result[1]?.isCurrent).toBe(false);
    });
  });

  describe('revokeSession', () => {
    it('should revoke a specific session', async () => {
      // Arrange
      const mockSessions = [
        {
          tokenId: 'token_1',
          userId: 'user_123',
          organizationId: 'org_123',
          role: 'owner',
          ipAddress: '192.168.1.1',
          userAgent: 'Chrome',
          createdAt: new Date().toISOString(),
          lastActivityAt: new Date().toISOString(),
        },
      ];
      mockAuthService.getUserSessions.mockResolvedValue(mockSessions);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.revokeSession('user_123', 'token_1');

      // Assert
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'auth.session.revoked',
        expect.objectContaining({
          userId: 'user_123',
          sessionId: 'token_1',
        })
      );
    });

    it('should throw error when session not found', async () => {
      // Arrange
      mockAuthService.getUserSessions.mockResolvedValue([]);

      // Act & Assert
      await expect(service.revokeSession('user_123', 'nonexistent_token')).rejects.toThrow(AppException);
    });
  });
});
